public interface IPrototype<T> {
  T Clone();
}

public class DocumentTemplate : IPrototype<DocumentTemplate> {
  public string Name { get; }
  public string Layout { get; }

  public DocumentTemplate(string name, string layout) {
    Name = name;
    Layout = layout;
  }

  public DocumentTemplate Clone() {
    return new DocumentTemplate(Name, Layout);
  }
}

UNIT_TEST_EXAMPLE:
[TestMethod]
public void Clone_ReturnsIndependentCopy() {
  var original = new DocumentTemplate("Invoice", "A4");
  var copy = original.Clone();

  Assert.AreNotSame(original, copy);
  Assert.AreEqual(original.Name, copy.Name);
  Assert.AreEqual(original.Layout, copy.Layout);
}

[TestMethod]
public void Clone_CanBeUsedAsTemplateForMultipleInstances() {
  var prototype = new DocumentTemplate("Receipt", "Thermal");
  var first = prototype.Clone();
  var second = prototype.Clone();

  Assert.AreNotSame(first, second);
  Assert.AreEqual("Receipt", first.Name);
  Assert.AreEqual("Receipt", second.Name);
}
